previewCss:
.darma-loader-darma-custom-499 {--loader-bg: var(--loader-bg, #ffffff);
  --loader-secondary-color: var(--loader-secondary-color, #22d3ee);
   width: 70px;
   aspect-ratio: 1;
   color: var(--loader-color, #0891b2);
   background: linear-gradient(currentColor 0 0) 50%/100% 15px, linear-gradient(currentColor 0 0) 50%/15px 100%, radial-gradient(circle 15px,currentColor 94%,#0000);
   background-repeat: no-repeat;
   -webkit-mask: radial-gradient(circle 5px,#0000 90%,currentColor);
   clip-path: polygon(0 30px,calc(100% - 30px) 0,100% calc(100% - 30px),30px 100%);
   animation: darma-loader-darma-custom-499-l5 1.5s infinite linear;
}
@keyframes darma-loader-darma-custom-499-l5  {
  100%{transform: rotate(1turn)}
}

